  ('heelevel3-6f0ba476-moex-00453', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '甲公司109年度（會計年度為曆年制）本期稅後淨利扣除依法提列項目及分派股利後之未分配盈 餘為300萬元。於110年3月購置符合「公司或有限合夥事業實質投資適用未分配盈餘減除及申 請退稅辦法」規定之A機器設備120萬元，下列敘述何者正確？', '["於110年5月申報109年度未分配盈餘，以180萬元加徵5%營利事業所得稅", "於110年5月申報109年度未分配盈餘，以300萬元加徵5%營利事業所得稅", "於111年5月申報109年度未分配盈餘，以300萬元加徵5%營利事業所得稅", "於111年5月申報109年度未分配盈餘，以180萬元加徵5%營利事業所得稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00454', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '甲公司製造商品時產生某些下腳與廢料，試問甲公司於國內銷售該等下腳與廢料所取得之代價， 應否開立發票？營業稅稅率為何？', '["應開發票，稅率為5%", "應開發票，稅率為0.1%", "免開發票，稅率為1%", "免開發票，免稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00455', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依加值型及非加值型營業稅法規定，小規模營業人得以當期購買營業上使用之貨物或勞務所取得 進項稅額之一定比例，扣減當期查定稅額，試問其得扣減金額為進項稅額之比例為何？若該項得 扣減金額超過查定稅額者，次期可否繼續扣減？', '["進項稅額之5%；次期可繼續扣減", "進項稅額之5%；次期不可繼續扣減", "進項稅額之10%；次期可繼續扣減", "進項稅額之10%；次期不可繼續扣減"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00456', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列何項貨物免課徵貨物稅？', '["彩色電視機", "電腦螢幕", "電冰箱", "電烤箱（以電熱或微波烤炙食物之器具）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00457', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '各行業關於營業稅額計算方式及稅率規定，依加值型及非加值型營業稅法，下列敘述何者錯誤？', '["有陪侍服務之酒吧，按特種稅額計算，其稅率為15%", "銀行業按特種稅額計算，經營專屬本業之銷售額，其稅率為5%", "農產品批發市場之承銷人及銷售農產品之小規模營業人，其營業稅稅率為0.1%", "百貨業按一般稅額計算，其稅率為5%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00458', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '林先生111年5月18日將其持有之臺南市土地1筆及房屋1棟贈與其子，贈與當時該土地之公 告土地現值為$4,000,000、房屋評定標準價格為$1,000,000，而土地與房屋之市價分別為$8,000,000 與$1,500,000，其子已成年，有正當職業並已小有積蓄，若該移轉之土地增值稅$300,000 與契稅 $60,000由其子支付，則此項贈與總額為何？', '["$4,640,000", "$5,000,000", "$9,140,000", "$9,500,000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00459', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '下列何者應計入遺產總額？', '["遺贈人、受遺贈人或繼承人捐贈公有事業機構或全部公股之公營事業之財產", "被繼承人自拍賣市場取得之著作權、發明專利權及藝術品", "被繼承人職業上之工具，其總價值在40萬元以下部分", "被繼承人死亡前5年內，繼承之財產已納遺產稅者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
