  ('heelevel3-6f0ba476-moex-00461', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-111-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '張先生於民國110年出售土地一塊，售價為4,500萬元，公告現值為3,000萬元，該筆土地是張先 生於民國85年以1,400萬元購得，當時的公告現值是600萬元，以購買時為基期換算申報土地移 轉現值收件當時已公告之最近臺灣地區消費者物價總指數為 150，張先生在購買土地當年曾支付 改良土地費用800萬元，則其應納土地增值稅為何？（不計入因重新規定地價而增繳地價稅之可 抵繳額）', '["180萬元", "292萬元", "300萬元", "320萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:31+00:00", "source_pdf_sha1": "2dd66111d1a6", "answer_pdf_sha1": "4da3144b64e9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "321", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
